@startuml
skinparam ClassDiagram labelStyle fontname "Helvetica"
skinparam Actor labelStyle fontname "Helvetica"
skinparam Interface labelStyle fontname "Helvetica"
skinparam Class labelStyle fontname "Helvetica"

class FantasticFactory {
    +FantasticFactory()
    -_page
    -_author
}

class FantasticBook {
    +FantasticBook()
    -_bookCategory
    -_page
    -_author
}

class BookFactory {
    +GetBook()
    +BookFactory()
}

class Book {
    +BookCategory
    +Page
    +Author
}

class ScienceFictionFactory {
    +ScienceFictionFactory()
    -_page
    -_author
}

class ScienceFictionBook {
    +ScienceFictionBook()
    -_bookCategory
    -_page
    -_author
}

FantasticFactory ..> FantasticBook : "1"
FantasticFactory ..> BookFactory : "1"
FantasticFactory ..> BookFactory : "1"

BookFactory ..> Book : "1"

ScienceFictionFactory ..> ScienceFictionBook : "1"
ScienceFictionFactory ..> BookFactory : "1"
ScienceFictionFactory ..> BookFactory : "1"

BookFactory ..> Book : "1"
ScienceFictionBook ..> Book : "1"

@enduml
